using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpStdioServer.Tools;

[McpServerToolType]
public sealed class FetchPostTool
{
    [McpServerTool("fetch_post"), Description("Fetches a post by ID from the JSONPlaceholder API.")]
    public static async Task<string> FetchPost(
        IHttpClientFactory httpClientFactory,
        ILogger<FetchPostTool> logger,
        [Description("The numeric post ID to retrieve (1-100).")] int id)
    {
        logger.LogInformation("Fetching post {PostId}", id);

        using var client = httpClientFactory.CreateClient("ExternalApi");
        var post = await client.GetFromJsonAsync($"/posts/{id}", PostJsonContext.Default.Post);

        if (post is null)
            return $"No post found with id {id}.";

        return $"""
            Title: {post.Title}
            Body:  {post.Body}
            """;
    }
}

public sealed record Post
{
    [JsonPropertyName("id")]
    public int Id { get; init; }

    [JsonPropertyName("title")]
    public string Title { get; init; } = "";

    [JsonPropertyName("body")]
    public string Body { get; init; } = "";
}

[JsonSerializable(typeof(Post))]
internal sealed partial class PostJsonContext : JsonSerializerContext;

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpStdioServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt("summarize"), Description("Generates a prompt that asks for a concise summary of the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum number of sentences for the summary.")] int? maxSentences = null)
    {
        var constraint = maxSentences.HasValue
            ? $" Use no more than {maxSentences.Value} sentence(s)."
            : "";

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Type = "text",
                    Text = $"Please provide a concise summary of the following text.{constraint}\n\n{text}"
                }
            }
        ];
    }
}

